-- Seed current Kochlik homepage banners and migrated blog posts.
-- Run after add_kochlik_content_and_blogs.sql.
-- Safe Supabase SQL Editor format: all text/html is base64-decoded inside PostgreSQL.
-- Idempotent/non-destructive: existing blog slugs are skipped, and existing matching banners are not duplicated.

begin;

insert into public.kochlik_home_banners
  (owner_id, title, text, image_url, href, button_label, sort_order, is_active)
select
  'c28707c3-2289-48b9-bbd3-08a441fd02fc'::uuid,
  convert_from(decode('RGl6YWpub3bDqSBrdmV0aW7DocSNZQ==', 'base64'), 'UTF8'),
  convert_from(decode('VsOhxaFtdSBkb21vdnUsIHrDoWhyYWRlIGFsZWJvIGZpcm1lIGRvZGFqw7ogb3NvYml0bsO9IGNoYXJha3RlciBhIGljaCBuZXp2ecSNYWpuw6kgdHZhcnkgcMO0c29iaWEgdsO9bmltb8SNbmUgYSB2IGthxb5kb20gbsOhdsWhdGV2bsOta292aSB6YW5lY2hhasO6IHNpbG7DvSBkb2plbS4=', 'base64'), 'UTF8'),
  convert_from(decode('L2xlZ2FjeS9wb3QxLmpwZw==', 'base64'), 'UTF8'),
  convert_from(decode('L3Byb2R1a3Qta2F0ZWdvcmlhL2RpemFqbm92ZQ==', 'base64'), 'UTF8'),
  convert_from(decode('UG96cmllxaU=', 'base64'), 'UTF8'),
  10,
  true
where not exists (
  select 1
  from public.kochlik_home_banners existing
  where existing.owner_id = 'c28707c3-2289-48b9-bbd3-08a441fd02fc'::uuid
    and existing.title = convert_from(decode('RGl6YWpub3bDqSBrdmV0aW7DocSNZQ==', 'base64'), 'UTF8')
    and existing.href = convert_from(decode('L3Byb2R1a3Qta2F0ZWdvcmlhL2RpemFqbm92ZQ==', 'base64'), 'UTF8')
);

